import assert from 'node:assert/strict'
import { test } from 'node:test'
import {
  geo,
  geoDistance,
  geoFromHeaders,
  isInRegion,
} from './geo'

test('geo() extracts fields from Vercel headers', () => {
  const headers = new Headers({
    'x-vercel-ip-city': 'San Francisco',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'CA',
    'x-vercel-ip-latitude': '37.7749',
    'x-vercel-ip-longitude': '-122.4194',
    'x-vercel-ip-timezone': 'America/Los_Angeles',
  })

  const result = geo({ headers })

  assert.equal(result.city, 'San Francisco')
  assert.equal(result.countryCode, 'US')
  assert.equal(result.country, 'United States')
  assert.equal(result.region, 'CA')
  assert.equal(result.latitude, '37.7749')
  assert.equal(result.longitude, '-122.4194')
  assert.equal(result.timezone, 'America/Los_Angeles')
})

test('geoFromHeaders() uses cf-ipcountry as fallback when x-vercel-ip-country is absent', () => {
  const headers = new Headers({
    'cf-ipcountry': 'DE',
  })

  const result = geoFromHeaders(headers)

  assert.equal(result.countryCode, 'DE')
  assert.equal(result.country, 'Germany')
  assert.equal(result.city, undefined)
  assert.equal(result.region, undefined)
})

test('geoFromHeaders() prefers x-vercel-ip-country over cf-ipcountry', () => {
  const headers = new Headers({
    'x-vercel-ip-country': 'FR',
    'cf-ipcountry': 'DE',
  })

  const result = geoFromHeaders(headers)

  assert.equal(result.countryCode, 'FR')
  assert.equal(result.country, 'France')
})

test('geo() returns undefined fields when headers are missing', () => {
  const headers = new Headers()
  const result = geo({ headers })

  assert.equal(result.city, undefined)
  assert.equal(result.country, undefined)
  assert.equal(result.countryCode, undefined)
  assert.equal(result.region, undefined)
  assert.equal(result.latitude, undefined)
  assert.equal(result.longitude, undefined)
  assert.equal(result.timezone, undefined)
})

test('geo() looks up country name from countryCode', () => {
  const cases: Array<[string, string]> = [
    ['AU', 'Australia'],
    ['BR', 'Brazil'],
    ['CA', 'Canada'],
    ['CN', 'China'],
    ['GB', 'United Kingdom'],
    ['IN', 'India'],
    ['JP', 'Japan'],
  ]

  for (const [code, name] of cases) {
    const headers = new Headers({ 'x-vercel-ip-country': code })
    const result = geo({ headers })
    assert.equal(result.country, name, `Expected country name for ${code}`)
  }
})

test('geo() returns undefined country for unknown countryCode', () => {
  const headers = new Headers({ 'x-vercel-ip-country': 'ZZ' })
  const result = geo({ headers })

  assert.equal(result.countryCode, 'ZZ')
  assert.equal(result.country, undefined)
})

test('isInRegion() returns true when countryCode is in the list', () => {
  const geoData = { countryCode: 'US' }
  assert.equal(isInRegion(geoData, ['US', 'CA', 'MX']), true)
})

test('isInRegion() returns false when countryCode is not in the list', () => {
  const geoData = { countryCode: 'DE' }
  assert.equal(isInRegion(geoData, ['US', 'CA', 'MX']), false)
})

test('isInRegion() performs case-insensitive comparison', () => {
  const geoData = { countryCode: 'us' }
  assert.equal(isInRegion(geoData, ['US']), true)

  const geoData2 = { countryCode: 'US' }
  assert.equal(isInRegion(geoData2, ['us']), true)
})

test('isInRegion() returns false when countryCode is undefined', () => {
  const geoData = {}
  assert.equal(isInRegion(geoData, ['US', 'CA']), false)
})

test('geoDistance() calculates Haversine distance between New York and London within 50km tolerance', () => {
  // New York: 40.7128° N, 74.0060° W
  // London:   51.5074° N,  0.1278° W
  // Expected: ~5,570 km
  const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')

  assert.ok(
    Math.abs(distance - 5570) <= 50,
    `Expected ~5570 km, got ${distance.toFixed(1)} km`
  )
})

test('geoDistance() returns 0 for identical points', () => {
  const distance = geoDistance('48.8566', '2.3522', '48.8566', '2.3522')
  assert.equal(distance, 0)
})

test('geoDistance() calculates Sydney to Tokyo within 50km tolerance', () => {
  // Sydney:  -33.8688° S, 151.2093° E
  // Tokyo:    35.6762° N, 139.6503° E
  // Expected: ~7,823 km
  const distance = geoDistance('-33.8688', '151.2093', '35.6762', '139.6503')

  assert.ok(
    Math.abs(distance - 7823) <= 50,
    `Expected ~7823 km, got ${distance.toFixed(1)} km`
  )
})

